/**
 * CTS BPO — AI Email Outreach & Marketing Engine
 * Full sales funnel templates: Cold Outreach → Negotiation → Contract → Invoice → Payment → Completion
 * Sends via Gmail SMTP (App Password). Falls back to console log when unconfigured.
 */

const nodemailer  = require('nodemailer');
const axios       = require('axios');
const auditLogger = require('./audit-logger');

const GMAIL_USER      = process.env.GMAIL_USER         || process.env.SMTP_USER || '';
const GMAIL_APP_PASS  = (process.env.GMAIL_APP_PASSWORD  || process.env.SMTP_PASS || '').replace(/\s+/g, '');
const SMTP_HOST       = process.env.SMTP_HOST           || 'smtp.gmail.com';
const SMTP_PORT       = parseInt(process.env.SMTP_PORT  || '587', 10);
const MAILGUN_KEY     = process.env.MAILGUN_API_KEY     || '';
const MAILGUN_DOMAIN  = process.env.MAILGUN_DOMAIN      || '';
const MAILJET_API_KEY    = process.env.MAILJET_API_KEY     || '';
const MAILJET_SEC_KEY    = process.env.MAILJET_SECRET_KEY  || '';
const MAILERLITE_API_KEY = process.env.MAILERLITE_API_KEY  || '';
const FROM_NAME       = 'Calvin Thomas';
const FROM_EMAIL      = process.env.FROM_EMAIL || GMAIL_USER || 'cts.bposolutions@gmail.com';
const REPLY_EMAIL     = 'cts.cybersolutions@gmail.com';
const WEBSITE         = 'cts.bposolutions@gmail.com';

// Rate limit: ms between sends. Default 200ms (5/sec). Set EMAIL_RATE_MS=50 for SendGrid paid plans.
const EMAIL_RATE_MS   = parseInt(process.env.EMAIL_RATE_MS || '200', 10);

// Per-provider daily caps (99% threshold = stop before hard limits)
// MailerLite free: 1000/day | Mailjet: 299/day | Gmail: 500/day | SendGrid free: 100/day | Mailgun: 99/day
const PROVIDER_CAPS = { mailerlite: 399, mailjet: 299, gmail: 500, mailgun: 99 };
function getProviderCap() { return PROVIDER_CAPS[getSenderMode()] || 500; }
function getStopAt()      { return Math.floor(getProviderCap() * 0.99); }   // 99% rule

let dailySentCount = 0;
let dailyResetDate = new Date().toDateString();

// Load persisted send count per provider — so restarts don't reset mid-day,
// but switching providers starts fresh for that provider.
(function loadPersistedCount() {
  try {
    const fs      = require('fs');
    const path    = require('path');
    const file    = path.join(__dirname, '../../data/outreach-stats.json');
    const mode    = getSenderMode();
    if (fs.existsSync(file)) {
      const data  = JSON.parse(fs.readFileSync(file, 'utf8'));
      const today = new Date().toDateString();
      // Per-provider bucket (new format) — fall back to legacy global only for matching provider
      const bucket = data[mode];
      if (bucket && bucket.todayDate === today) {
        dailySentCount = bucket.sentToday || 0;
        dailyResetDate = today;
        console.log(`[EMAIL] Restored ${mode} daily sent count: ${dailySentCount}`);
      } else if (!bucket && data.todayDate === today && mode === (data.provider || 'gmail')) {
        // Legacy format — only restore if same provider
        dailySentCount = data.sentToday || 0;
        dailyResetDate = today;
        console.log(`[EMAIL] Restored legacy sent count for ${mode}: ${dailySentCount}`);
      } else {
        console.log(`[EMAIL] Provider switched to ${mode} — starting fresh at 0`);
      }
    }
  } catch (e) { /* ignore */ }
})();

// Persist per-provider daily count to disk so the dashboard reflects live sends
const _statsFs   = require('fs');
const _statsPath = require('path').join(__dirname, '../../data/outreach-stats.json');
function savePerProviderCount() {
  try {
    const mode   = getSenderMode();
    const today  = new Date().toDateString();
    let existing = {};
    try { existing = JSON.parse(_statsFs.readFileSync(_statsPath, 'utf8')); } catch {}
    existing[mode] = { sentToday: dailySentCount, todayDate: today };
    _statsFs.writeFileSync(_statsPath, JSON.stringify(existing, null, 2));
  } catch {}
}

function checkDailyReset() {
  const today = new Date().toDateString();
  if (today !== dailyResetDate) { dailySentCount = 0; dailyResetDate = today; }
}

function dailyCapReached() {
  checkDailyReset();
  return dailySentCount >= getStopAt();   // stop at 99% of provider cap
}

// ── Global email pause flag ───────────────────────────────────────────────────
// Persisted to disk so it survives restarts. Starts PAUSED until explicitly enabled.
const PAUSE_FILE = require('path').join(__dirname, '../../data/email-pause.json');
let emailPaused = true;   // default: paused

(function loadPauseState() {
  try {
    const fs = require('fs');
    if (fs.existsSync(PAUSE_FILE)) {
      const d = JSON.parse(fs.readFileSync(PAUSE_FILE, 'utf8'));
      emailPaused = !!d.paused;
      console.log(`[EMAIL] Pause state loaded: ${emailPaused ? '⏸ PAUSED' : '▶ ACTIVE'}`);
    } else {
      savePauseState();   // write default (paused)
      console.log('[EMAIL] No pause file found — defaulting to ⏸ PAUSED');
    }
  } catch (e) { /* keep default */ }
})();

function savePauseState() {
  try {
    const fs = require('fs');
    fs.writeFileSync(PAUSE_FILE, JSON.stringify({ paused: emailPaused, updatedAt: new Date().toISOString() }, null, 2));
  } catch {}
}

function setEmailPaused(val) {
  emailPaused = !!val;
  savePauseState();
  console.log(`[EMAIL] Outreach ${emailPaused ? '⏸ PAUSED' : '▶ RESUMED'} by admin`);
}

function isEmailPaused() { return emailPaused; }

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

// ── Sender detection — priority: MailerLite > Mailgun > Mailjet > Gmail ──────
// Providers that returned 404/403 (feature not enabled) are skipped for the session
const _brokenProviders = new Set();
function markBroken(provider) {
  if (!_brokenProviders.has(provider)) {
    _brokenProviders.add(provider);
    console.warn(`[EMAIL] ⚠️ Provider '${provider}' marked broken (404/403) — falling back to next provider`);
  }
}

function getSenderMode() {
  if (MAILERLITE_API_KEY && !_brokenProviders.has('mailerlite'))                 return 'mailerlite';
  if (MAILGUN_KEY && MAILGUN_DOMAIN && !_brokenProviders.has('mailgun'))         return 'mailgun';
  if (MAILJET_API_KEY && MAILJET_SEC_KEY && !_brokenProviders.has('mailjet'))    return 'mailjet';
  if (GMAIL_USER && GMAIL_APP_PASS && !_brokenProviders.has('gmail'))            return 'gmail';
  return null;
}

function isConfigured() { return !!getSenderMode(); }
function areAllProvidersBroken() { return getSenderMode() === null; }

// ── Gmail SMTP transporter ──────────────────────────────────────────────────
let transporter = null;
function getTransporter() {
  if (transporter) return transporter;
  console.log(`[EMAIL] Config — mode:${getSenderMode()||'NONE'} user:${GMAIL_USER||'(not set)'} pass_len:${GMAIL_APP_PASS.length} host:${SMTP_HOST}:${SMTP_PORT}`);
  if (GMAIL_USER && GMAIL_APP_PASS) {
    transporter = nodemailer.createTransport({
      host: SMTP_HOST, port: SMTP_PORT,
      secure: SMTP_PORT === 465,
      auth: { user: GMAIL_USER, pass: GMAIL_APP_PASS },
      pool: true, maxConnections: 5, maxMessages: 100,
    });
    // Remove the X-Mailer header so recipients can't see "nodemailer"
    transporter.use('compile', (mail, next) => {
      mail.data.headers = { ...(mail.data.headers || {}), 'X-Mailer': undefined };
      next();
    });
  }
  return transporter;
}

// ── Core send function — routes to correct provider ─────────────────────────
async function sendMail({ to, subject, html, text, replyTo }) {
  if (isEmailPaused()) {
    console.log(`[EMAIL] ⏸ Outreach paused — skipping send to ${to}`);
    return { skipped: true, reason: 'paused' };
  }
  if (dailyCapReached()) {
    console.warn(`[EMAIL] 99% cap (${getStopAt()}/${getProviderCap()}) reached — skipping send to ${to}`);
    return { skipped: true, reason: 'daily_cap' };
  }

  const mode = getSenderMode();
  if (!mode) {
    console.warn(`[EMAIL] All providers broken — cannot send to ${to}, skipping`);
    return { error: true, allProvidersBroken: true, sent: false };
  }

  const fromStr = `${FROM_NAME} <${FROM_EMAIL}>`;

  try {
    if (mode === 'mailerlite') {
      // MailerLite transactional email API v3
      await axios.post('https://connect.mailerlite.com/api/emails', {
        from:     FROM_EMAIL,
        from_name: FROM_NAME,
        to: [{ email: to }],
        reply_to: replyTo || REPLY_EMAIL,
        subject,
        html,
        ...(text ? { text } : {}),
      }, {
        headers: {
          Authorization: `Bearer ${MAILERLITE_API_KEY}`,
          'Content-Type': 'application/json',
          Accept: 'application/json',
        },
        timeout: 12000,
      });

    } else if (mode === 'mailjet') {
      await axios.post('https://api.mailjet.com/v3.1/send', {
        Messages: [{
          From:     { Email: FROM_EMAIL, Name: FROM_NAME },
          To:       [{ Email: to }],
          ReplyTo:  { Email: replyTo || REPLY_EMAIL },
          Subject:  subject,
          HTMLPart: html,
          ...(text ? { TextPart: text } : {}),
        }],
      }, {
        auth:    { username: MAILJET_API_KEY, password: MAILJET_SEC_KEY },
        headers: { 'Content-Type': 'application/json' },
        timeout: 10000,
      });

    } else if (mode === 'mailgun') {
      const FormData = require('form-data');
      const form = new FormData();
      form.append('from', fromStr);
      form.append('to', to);
      form.append('subject', subject);
      form.append('html', html);
      if (text) form.append('text', text);
      if (replyTo) form.append('h:Reply-To', replyTo);
      await axios.post(
        `https://api.mailgun.net/v3/${MAILGUN_DOMAIN}/messages`,
        form,
        { auth: { username: 'api', password: MAILGUN_KEY }, timeout: 10000 }
      );

    } else {
      // Gmail SMTP
      const t = getTransporter();
      const mailOpts = { from: fromStr, to, subject, html, replyTo: replyTo || REPLY_EMAIL };
      if (text) mailOpts.text = text;
      await t.sendMail(mailOpts);
    }

    dailySentCount++;
    savePerProviderCount();
    if (EMAIL_RATE_MS > 0) await sleep(EMAIL_RATE_MS);
    return { sent: true, mode };

  } catch (err) {
    const status = err.response?.status || 0;
    if (status >= 400 && status < 500) {
      const msg = err.response?.data?.errors?.[0]?.message || err.response?.data?.message || err.message;
      // 404 / 403 = feature not enabled; 401 = bad credentials → mark broken, try next provider
      if (status === 404 || status === 403 || status === 401) {
        markBroken(mode);
        const nextMode = getSenderMode();
        if (nextMode) {
          console.log(`[EMAIL] Retrying via fallback provider: ${nextMode}`);
          return sendMail({ to, subject, html, text, replyTo }); // recurse with next provider
        }
        console.error(`[EMAIL] All providers broken — no working email provider configured`);
        return { error: true, allProvidersBroken: true, status, message: 'All email providers unavailable — check API credentials' };
      }
      // 422 / 400 / other 4xx = bad email address — log and skip, don't mark provider broken
      console.error(`[EMAIL] ${mode} ${status} error sending to ${to}: ${msg}`);
      return { error: true, status, message: msg };
    }
    // SMTP / network errors (nodemailer Gmail, connection errors)
    const smtpCode = err.responseCode || 0; // nodemailer sets responseCode
    const isGmailAuthErr = mode === 'gmail' && (smtpCode === 535 || err.code === 'EAUTH' || /535|authentication|credentials|login/i.test(err.message));
    if (isGmailAuthErr) {
      console.error(`[EMAIL] Gmail SMTP auth failure — marking broken: ${err.message}`);
      markBroken('gmail');
      return { error: true, status: 535, message: `Gmail auth failed: ${err.message}` };
    }
    // Gmail daily sending limit (550 5.4.5) — mark as broken, then fall through to check remaining providers
    const isGmailDailyLimit = mode === 'gmail' && (smtpCode === 550 || /550.*5\.4\.5|Daily.*sending.*limit|user sending limit/i.test(err.message));
    if (isGmailDailyLimit) {
      console.error(`[EMAIL] Gmail daily sending limit reached — marking broken for this session`);
      markBroken('gmail');
      const nextMode = getSenderMode();
      if (nextMode) {
        console.log(`[EMAIL] Retrying via fallback provider: ${nextMode}`);
        return sendMail({ to, subject, html, text, replyTo });
      }
      console.error(`[EMAIL] All providers broken — no working email provider configured`);
      return { error: true, allProvidersBroken: true, status: 550, message: 'Gmail daily limit reached — all providers exhausted' };
    }
    // For API providers (not Gmail), connection errors mean the provider is unreachable — mark broken & fall through
    if (mode !== 'gmail' && (err.code === 'ECONNRESET' || err.code === 'ECONNREFUSED' || err.code === 'ETIMEDOUT' || err.code === 'ENOTFOUND')) {
      console.error(`[EMAIL] ${mode} connection error (${err.code}) — marking broken and falling back`);
      markBroken(mode);
      const nextMode = getSenderMode();
      if (nextMode) {
        console.log(`[EMAIL] Retrying via fallback provider: ${nextMode}`);
        return sendMail({ to, subject, html, text, replyTo });
      }
      console.error(`[EMAIL] All providers broken — no working email provider configured`);
      return { error: true, allProvidersBroken: true, status: 0, message: 'All email providers unavailable' };
    }
    console.error(`[EMAIL] ${mode} SMTP/network error to ${to}: ${err.message}`);
    return { error: true, status: 0, message: err.message };
  }
}

function esc(str) {
  if (typeof str !== 'string') return '';
  return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

